import os
import time
import jwt

JWT_SECRET = os.getenv("JWT_SECRET", "CHANGE_ME")
JWT_ALGORITHM = os.getenv("JWT_ALGORITHM", "HS256")
JWT_ISSUER = os.getenv("JWT_ISSUER", "your-service")
JWT_AUDIENCE = os.getenv("JWT_AUDIENCE", "your-clients")
JWT_TTL_SECONDS = int(os.getenv("JWT_TTL_SECONDS", "3600"))


def generate_jwt(user_id: str, role: str, *, ttl_seconds: int = None, secret: str = None) -> str:
    now = int(time.time())
    ttl = JWT_TTL_SECONDS if ttl_seconds is None else int(ttl_seconds)

    payload = {
        "sub": str(user_id),
        "role": str(role),
        "iat": now,
        "nbf": now,
        "exp": now + ttl,
        "iss": JWT_ISSUER,
        "aud": JWT_AUDIENCE,
    }

    token = jwt.encode(payload, secret or JWT_SECRET, algorithm=JWT_ALGORITHM)
    if isinstance(token, bytes):
        token = token.decode("utf-8")
    return token


def verify_jwt(token: str, *, secret: str = None) -> dict:
    return jwt.decode(
        token,
        secret or JWT_SECRET,
        algorithms=[JWT_ALGORITHM],
        issuer=JWT_ISSUER,
        audience=JWT_AUDIENCE,
        options={"require": ["exp", "iat", "nbf", "sub"]},
    )